// // This module selects between two 32-bit inputs based on a single-bit address input. When address is 0, the output is assigned to input1; when address is 1, the output is assigned to input0.
module top_module(
output [31:0] out,
input         address,
input  [31:0] input0, input1
);wire [31:0] mux [1:0];
  assign mux[0] = input0;
  assign mux[1] = input1;

  assign out = mux[address];
endmodule
